use std::io::{self, Stdin};
use std::str::{self, FromStr};
use std::error::Error;
use std::thread;

fn exec() {
    let mut sc = Scanner::new();
    let s: String = sc.ne();
    let t: String = sc.ne();
    fn f(s: &str) -> i32 {
        match s {
            "monday" => 0,
            "tuesday" => 1,
            "wednesday" => 2,
            "thursday" => 3,
            "friday" => 4,
            "saturday" => 5,
            "sunday" => 6,
            _ => panic!(">_<"),
        }
    }
    let s = f(&s);
    let t = f(&t);
    let mut ok = false;
    for &x in &[28, 30, 31] {
        if (s + x) % 7 == t {
            ok = true;
            break;
        }
    }
    println!("{}", if ok { "YES" } else { "NO" });
}

fn main() {
    const DEFAULT_STACK: usize = 16 * 1024 * 1024;
    let builder = thread::Builder::new();
    let th = builder.stack_size(DEFAULT_STACK);
    let handle = th.spawn(|| { exec(); }).unwrap();
    let _ = handle.join();
}

